            //
            aPrevious = aIngress;
            //
            aIngress = (RotL64(aSnowLaneA[((aIndex + 273U)) & S_BLOCK1], 36U) ^ RotL64(aSnowLaneB[((aIndex + 903U)) & S_BLOCK1], 5U));
