            //
            aScatter = (RotL64(aIngress, 37U) + RotL64(aCarry, 5U)) + (RotL64(aPrevious, 19U) ^ RotL64(aCross, 54U));
            aScatter = TwistMix64::DiffuseA(aScatter);
            //
            aOrbiterJ = ((aWandererC + RotL64(aScatter, 47U)) + 0x7D1B6DF90CB71E10ULL) + aPhaseDOrbiterAssignSaltA[((aIndex + 17U)) & S_SALT1];
            aOrbiterA = (aWandererE + RotL64(aCross, 35U)) + 0xD9D0C0FCB57E8114ULL;
            aOrbiterC = ((aWandererB + RotL64(aPrevious, 41U)) + RotL64(aCarry, 5U)) + 0x1D8962F065E56B50ULL;
