            aOrbiterG = RotL64((aOrbiterG * 0x42A3693A8AF518A3ULL), 13U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterF) + 0x8B5C9634B32FAE15ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterD) ^ 0xDD1C20E031ACA5F0ULL;
