            aCross = (RotL64(aSnowLaneA[((S_BLOCK1 - aIndex + 9005U)) & S_BLOCK1], 3U) ^ RotL64(aSnowLaneD[((S_BLOCK1 - aIndex + 10047U)) & S_BLOCK1], 58U));
