            aScatter = (RotL64(aCross, 39U) + RotL64(aIngress, 6U)) ^ (RotL64(aCarry, 21U) + RotL64(aPrevious, 57U));
            aScatter = TwistMix64::DiffuseA(aScatter);
            //
            aOrbiterG = (((aWandererH + RotL64(aIngress, 3U)) + RotL64(aCarry, 41U)) + 0x18617E7D1526CC0CULL) + aPhaseCOrbiterAssignSaltD[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterB = ((aWandererE + RotL64(aCross, 37U)) + RotL64(aCarry, 53U)) + 0x51BDC27E3C716B90ULL;
            aOrbiterI = (aWandererK + RotL64(aScatter, 13U)) + 0xA7A6604497ED7154ULL;
            aOrbiterF = (((aWandererC + RotL64(aPrevious, 54U)) + RotL64(aCarry, 5U)) + 0x1BA0DBCAB40593A3ULL) + aPhaseCOrbiterAssignSaltC[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterH = (aWandererJ + RotL64(aScatter, 21U)) + 0x4C27099642DDDD7EULL;
            aOrbiterE = (aWandererF + RotL64(aCross, 27U)) + 0x967B6F70E025A366ULL;
            aOrbiterA = (aWandererA + RotL64(aIngress, 47U)) + 0xBCE1D9812E24121BULL;
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0x86E434E45B1B7018ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterG) ^ 0x2AAE932024EF14F7ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x5425EF5877F6AD1BULL), 57U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterH) + 0x979355AC85D89BB6ULL) + aPhaseCOrbiterUpdateSaltF[((aIndex + 22U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0x3964CB509AE31AAAULL;
            aOrbiterB = RotL64((aOrbiterB * 0xF3EFA1A4C3F45EFBULL), 51U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterG) + 0x21E74443750559B4ULL) + aPhaseCOrbiterUpdateSaltE[((aIndex + 21U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 0xB872C1B7D77B0E03ULL;
