            aOrbiterE = (aOrbiterE + aOrbiterI) + 0xC5F9862E81342D74ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 0x681626F55786DCF8ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x14ABF8EF86D8F0FBULL), 5U);
