            aOrbiterB = (aOrbiterB + aOrbiterE) + 0x761B3B70566E26DFULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterB) ^ 0x9579F93B7B996C35ULL) ^ aPhaseCOrbiterUpdateSaltA[((aIndex + 17U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0x4B6FE9CF3CCDF077ULL), 13U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterA) + 0x1D688529C572BC08ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterI) ^ 0xDE29E1B2DF5ED153ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xB953386FCBD07DFBULL), 19U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0xE24954A0B7411CBAULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterA) ^ 0x582D5F27D84895B5ULL) ^ aPhaseCOrbiterUpdateSaltB[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 0xB406CF66F64339CBULL), 29U);
            //
            aIngress = RotL64(aOrbiterB, 3U) ^ aOrbiterI;
            aIngress = aIngress + (RotL64(aOrbiterA, 27U) ^ aOrbiterE);
            aIngress = aIngress + (aOrbiterH ^ RotL64(aOrbiterG, 37U));
            aIngress = aIngress + RotL64(aOrbiterF, 21U);
