            //
            aWandererC = aWandererC + ((RotL64(aPrevious, 5U) + aOrbiterB) + RotL64(aOrbiterE, 19U));
            aWandererA = aWandererA ^ ((RotL64(aScatter, 35U) + RotL64(aOrbiterA, 3U)) + aOrbiterB);
            aWandererK = aWandererK + (((RotL64(aCross, 14U) + RotL64(aOrbiterI, 13U)) + aOrbiterH) + RotL64(aCarry, 57U));
            aWandererJ = aWandererJ ^ (((RotL64(aIngress, 21U) + aOrbiterE) + RotL64(aOrbiterF, 27U)) + aPhaseCWandererUpdateSaltE[((aIndex + 27U)) & S_SALT1]);
            aWandererH = aWandererH + (((RotL64(aPrevious, 47U) + aOrbiterE) + RotL64(aOrbiterI, 51U)) + RotL64(aCarry, 19U));
            aWandererE = aWandererE ^ (((RotL64(aIngress, 57U) + aOrbiterG) + RotL64(aOrbiterH, 57U)) + aPhaseCWandererUpdateSaltD[(((31U - aIndex) + 5U)) & S_SALT1]);
            aWandererF = aWandererF + ((RotL64(aScatter, 29U) + RotL64(aOrbiterB, 36U)) + aOrbiterG);
            //
            aCarry = aCarry + (RotL64(aWandererF, 28U) ^ aWandererA);
