            aOrbiterD = RotL64((aOrbiterD * 0xAC404FA98F0E42F7ULL), 19U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 0x9308119125F32B31ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterC) ^ 0x302C5B6176C78D45ULL) ^ aPhaseBOrbiterUpdateSaltB[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 0x24766D406555A12FULL), 35U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterD) + 0x9304A38DF6437A37ULL) + aPhaseBOrbiterUpdateSaltA[((aIndex + 17U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterH) ^ 0x1BE62B2F5192CF83ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x0160D4F2CEDE8971ULL), 13U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 0x9A5CFD7CFC48F5F3ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 0x9102FABB58811293ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x940AB5F01F882833ULL), 47U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterA) + 0xD6025682FBA47EF8ULL;
            aOrbiterF = ((aOrbiterF ^ aOrbiterI) ^ 0xD48906BCC8E39E61ULL) ^ aPhaseBOrbiterUpdateSaltC[(((31U - aIndex) + 5U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0xCD250FAD52A11887ULL), 23U);
            //
            aIngress = aOrbiterE ^ RotL64(aOrbiterI, 13U);
