            aWandererC = aWandererC ^ ((RotL64(aIngress, 13U) + RotL64(aOrbiterF, 47U)) + aOrbiterG);
            aWandererF = aWandererF + (((RotL64(aCross, 6U) + aOrbiterI) + RotL64(aOrbiterC, 39U)) + aPhaseBWandererUpdateSaltD[(((31U - aIndex) + 11U)) & S_SALT1]);
            aWandererD = aWandererD ^ (((RotL64(aPrevious, 43U) + RotL64(aOrbiterE, 5U)) + aOrbiterD) + aPhaseBWandererUpdateSaltE[((aIndex + 8U)) & S_SALT1]);
            aWandererA = aWandererA + (((RotL64(aCross, 51U) + RotL64(aOrbiterJ, 13U)) + aOrbiterA) + RotL64(aCarry, 53U));
            aWandererK = aWandererK ^ ((RotL64(aPrevious, 35U) + RotL64(aOrbiterF, 23U)) + aOrbiterA);
            aWandererB = aWandererB + ((RotL64(aIngress, 27U) + RotL64(aOrbiterI, 54U)) + aOrbiterA);
            aWandererE = aWandererE ^ ((RotL64(aScatter, 23U) + aOrbiterJ) + RotL64(aOrbiterG, 35U));
            aWandererG = aWandererG + ((RotL64(aIngress, 58U) + RotL64(aOrbiterI, 19U)) + aOrbiterH);
