            //
            aOrbiterD = (((aWandererC + RotL64(aPrevious, 27U)) + RotL64(aCarry, 29U)) + 0x6D1C85AD10206A0FULL) + aPhaseHOrbiterAssignSaltF[((aIndex + 11U)) & S_SALT1];
            aOrbiterH = ((aWandererI + RotL64(aIngress, 19U)) + RotL64(aCarry, 39U)) + 0xE3DB168939D0906EULL;
            aOrbiterJ = (aWandererK + RotL64(aCross, 56U)) + 0x97ABEC570F9E1D75ULL;
            aOrbiterA = (aWandererD + RotL64(aScatter, 23U)) + 0xE83CB88E57B9D1DDULL;
