            aOrbiterB = (aWandererJ + RotL64(aScatter, 47U)) + 0xF0C5DCCE325E0A64ULL;
            aOrbiterC = ((aWandererB + RotL64(aCross, 51U)) + RotL64(aCarry, 11U)) + 0xF53EEA5122D630E5ULL;
            aOrbiterI = ((aWandererE + RotL64(aPrevious, 3U)) + 0x9A6EBC83CC05930CULL) + aPhaseHOrbiterAssignSaltE[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterK = (aWandererH + RotL64(aScatter, 36U)) + 0x34E2404D585A3284ULL;
            //
            aOrbiterD = ((aOrbiterD + aOrbiterH) + 0xC8E2DC85B1EA0B19ULL) + aPhaseHOrbiterUpdateSaltE[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterD) ^ 0x1CC362FBE83D2B99ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x1A5171C89D58F21FULL), 57U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 0xA322BB8ADB47F705ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterJ) ^ 0x4C7B94FECA360F2DULL;
            aOrbiterE = RotL64((aOrbiterE * 0x763B4E10A608D3DDULL), 5U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterB) + 0x10381734F48E9328ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0x9EBC61831A6727BBULL;
            aOrbiterC = RotL64((aOrbiterC * 0x457222B9AF4BAADBULL), 21U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterC) + 0x836A6DCAF50C22AAULL) + aPhaseHOrbiterUpdateSaltB[((aIndex + 20U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterE) ^ 0x7DB68F09010974C6ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x79849D1134E6EE99ULL), 13U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 0x9CB02A03E0E2DD39ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterI) ^ 0xE280E536860708DAULL;
            aOrbiterB = RotL64((aOrbiterB * 0x8CEDE7BE3412B8E3ULL), 43U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterI) + 0xAD39228D197A9E64ULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterH) ^ 0x3E3B43E219E0B02DULL) ^ aPhaseHOrbiterUpdateSaltA[((aIndex + 3U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0x2D957870381D6A5FULL), 51U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 0xF3C5C6724978DDD6ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 0x0C91D6C7E2B8C73EULL;
            aOrbiterD = RotL64((aOrbiterD * 0x7D293A1B518A244DULL), 29U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterE) + 0x6A8762A142EAA27AULL) + aPhaseHOrbiterUpdateSaltD[((aIndex + 18U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterK) ^ 0x234ACA8FCEAA4434ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x1344948AEDE83B61ULL), 47U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 0xD841ED9518772687ULL;
